    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: 'quote', items: [{ type: 'sword' }] },
        { op: 'quote', items: [{ type: 'sword' }] },
      ],
    });
    // First: 100 ×1.1 = 110, +5 = 115
    // Second: 100 ×0.85 = 85, +5 = 90
    expect(result.results).toEqual([{ premium: 115 }, { premium: 90 }]);
  });
});

